const json = $input.item.json;
const f = json.fields || json.Felder || {};

// Felder extrahieren
const thema   = f.field_1 || f.Field_1 || '(kein Thema)';
const bildUrl = f.field_8 || f.Field_8 || '';
const itemId  = parseInt(String(json.AUSWEIS || json.id || 0).trim(), 10);

// Ist Bild vorhanden? (nicht leer, nicht '0', nicht 0)
const hatBild = bildUrl && bildUrl !== '0' && bildUrl !== 0 && String(bildUrl).trim() !== '';

return {
  json: {
    ...json,
    thema:               thema,
    bild_url:            hatBild ? String(bildUrl).trim() : '',
    hat_bild:            hatBild,
    sharepoint_item_id:  itemId,
  }
};

// PFAD B: Bild bereits vorhanden – direkt verwenden
const json = $input.item.json;

return {
  json: {
    final_bild_url:      json.bild_url,
    thema:               json.thema,
    sharepoint_item_id:  json.sharepoint_item_id,
    bild_quelle:         'manuell',
    generated_at:        new Date().toISOString()
  }
};

// PFAD A: Canva Grafik generieren
const json = $input.item.json;

const systemPrompt = `Du bist ein Automatisierungsassistent für Physio Fuchs Social Media Grafiken.

Führe diese Schritte VOLLSTÄNDIG und NACHEINANDER aus:
1. Starte eine Editing-Session für Canva Design ID: DAG_tS-3P0k
2. Ersetze auf Seite 3 den Text "THEMA" durch den Thema-Text (element_id: PB3DLldpqyKKJNBj-LBRqHYLk6GzfMW2G)
3. Committe die Änderung
4. Exportiere das Design (Seite 3) als PNG
5. Warte bis der Export-Link verfügbar ist
6. Antworte AUSSCHLIESSLICH mit diesem JSON (kein Markdown):
{"export_url":"URL","thema":"TEXT","status":"success"}`;

return {
  json: {
    model: 'claude-sonnet-4-20250514',
    max_tokens: 4000,
    system: systemPrompt,
    messages: [{
      role: 'user',
      content: `Thema: ${json.thema}\nBitte ersetze THEMA mit "${json.thema}" und exportiere Seite 3 als PNG.`
    }],
    mcp_servers: [{
      type: 'url',
      url: 'https://mcp.canva.com/mcp',
      name: 'canva'
    }],
    _meta: {
      sharepoint_item_id: json.sharepoint_item_id,
      thema: json.thema
    }
  }
};

const response = $input.item.json;
const prev = $('Build Canva Payload').item.json._meta;

const content = response.content || [];
let exportUrl = '';
let thema = prev?.thema || '';

for (const block of content) {
  if (block.type === 'text' && block.text) {
    const text = block.text.trim();
    try {
      const cleaned = text.replace(/```json\n?/gi,'').replace(/```\n?/g,'').trim();
      const parsed = JSON.parse(cleaned);
      exportUrl = parsed.export_url || '';
      thema = parsed.thema || thema;
      break;
    } catch(e) {
      const urlMatch = text.match(/https?:\/\/[^\s"']+/g);
      if (urlMatch) {
        const canvaUrl = urlMatch.find(u => u.includes('canva') || u.includes('export'));
        exportUrl = canvaUrl || urlMatch[0];
      }
    }
  }
}

if (!exportUrl) {
  throw new Error('Kein Export-URL in Claude Antwort. Response: ' + JSON.stringify(response).substring(0, 400));
}

return {
  json: {
    final_bild_url:      exportUrl,
    thema:               thema,
    sharepoint_item_id:  prev?.sharepoint_item_id || 0,
    bild_quelle:         'canva',
    generated_at:        new Date().toISOString()
  }
};
